function loadSeedData() {
  // Only seed if localStorage is empty
  let existing = JSON.parse(localStorage.getItem('kz_reservations') || '[]');
  if (!existing.length) {
    localStorage.setItem('kz_reservations', JSON.stringify(SEED_RESERVATIONS));
    console.log('Seeded ' + SEED_RESERVATIONS.length + ' reservations');
  }
  let existingPay = JSON.parse(localStorage.getItem('kz_payments') || '[]');
  if (!existingPay.length) {
    localStorage.setItem('kz_payments', JSON.stringify(SEED_PAYMENTS));
    console.log('Seeded ' + SEED_PAYMENTS.length + ' payments');
  }
}
